def process_data(data_list, min_length):
    if data_list is None:
        raise ValueError("Data cannot be None.")

    if not isinstance(data_list, list):
        raise TypeError("Data must be a list.")

    if len(data_list) < min_length:
        raise ValueError(f"Data list is too short. Expected at least {min_length} items, got {len(data_list)}.")

    # Ana iş mantığı buraya gelir.
    # Bu noktaya geldiğimizde, data_list'in None olmadığı, bir liste olduğu ve yeterli uzunlukta olduğu garanti edilmiştir.

    total = sum(data_list)
    average = total / len(data_list) if data_list else 0 # Boş liste durumunu da ele alalım, guard clause'dan geçse bile

    return f"Processed {len(data_list)} items. Sum: {total}, Average: {average:.2f}"
